<div class="sb-setup-wrap">
<style>
:root{
  --ink:#1f2937;--ink-sub:#6b7280;--ink-faint:#a8acb3;
  --paper:#f5f3ee;--paper-2:#fbf9f4;--paper-3:#ece8dd;
  --line:rgba(26,42,58,.12);--line-faint:rgba(26,42,58,.06);
  --gold:#b89968;--gold-soft:#d4b88a;--red:#9a1b29;--green:#4f6b5c;
  --font-cn:'Source Han Serif SC','Songti SC',serif;
  --font-en:'Cormorant Garamond',Georgia,serif;
  --font-sans:-apple-system,'PingFang SC','Helvetica Neue',sans-serif;
}
.sb-setup-wrap{max-width:560px;margin:24px auto;font-family:var(--font-sans);color:var(--ink);}
.sb-setup{background:var(--paper);border:.5px solid var(--line);border-radius:8px;padding:48px 56px 44px;box-shadow:0 22px 60px rgba(26,42,58,.10),0 1px 3px rgba(26,42,58,.05);position:relative;overflow:hidden;}
.sb-setup::before{content:'';position:absolute;top:-60px;left:-60px;width:240px;height:240px;background:radial-gradient(circle,rgba(184,153,104,.22),transparent 70%);pointer-events:none;filter:blur(40px);}
.sb-setup::after{content:'';position:absolute;bottom:-60px;right:-60px;width:200px;height:200px;background:radial-gradient(circle,rgba(154,27,41,.06),transparent 70%);pointer-events:none;filter:blur(50px);}
.sb-setup>*{position:relative;z-index:1;}

.sb-setup-h{text-align:center;padding-bottom:24px;margin-bottom:28px;border-bottom:.5px solid var(--line);}
.sb-setup-eyebrow{font-family:var(--font-en);font-size:10px;letter-spacing:5px;text-transform:uppercase;color:var(--gold);font-weight:700;}
.sb-setup-title{font-family:var(--font-cn);font-size:30px;font-weight:500;color:var(--ink);letter-spacing:6px;margin:14px 0 6px;}
.sb-setup-sub{font-family:var(--font-en);font-style:italic;font-size:13px;color:var(--ink-sub);letter-spacing:2px;}

.sb-setup-quote{font-family:var(--font-cn);font-size:14px;line-height:1.85;color:var(--ink-sub);text-align:center;letter-spacing:.5px;margin:0 0 32px;padding:0 8px;}
.sb-setup-quote::before,.sb-setup-quote::after{content:'· · · · · · · · · · · ·';display:block;color:var(--gold);font-size:9px;letter-spacing:3px;opacity:.5;margin:10px 0;}

.sb-row{margin-bottom:18px;}
.sb-row.sb-pair{display:flex;gap:14px;}
.sb-row.sb-pair > .sb-row{flex:1;margin:0;}

.sb-label{display:flex;align-items:baseline;gap:8px;margin-bottom:6px;}
.sb-label-en{font-family:var(--font-en);font-size:10px;letter-spacing:3px;text-transform:uppercase;color:var(--gold);font-weight:600;}
.sb-label-cn{font-family:var(--font-cn);font-size:13px;color:var(--ink);letter-spacing:1px;}

.sb-input,.sb-select,.sb-textarea{width:100%;box-sizing:border-box;background:var(--paper-2);border:none;border-bottom:.5px solid var(--gold-soft);color:var(--ink);font-family:var(--font-cn);font-size:14.5px;padding:8px 4px;letter-spacing:.5px;outline:none;transition:border-color .25s;}
.sb-input:focus,.sb-select:focus,.sb-textarea:focus{border-bottom-color:var(--gold);}
.sb-input::placeholder,.sb-textarea::placeholder{color:var(--ink-faint);font-style:italic;font-family:var(--font-en);font-size:13px;letter-spacing:1px;}
.sb-textarea{resize:none;min-height:60px;border:.5px solid var(--gold-soft);border-radius:4px;padding:10px 12px;line-height:1.7;}
.sb-select{appearance:none;-webkit-appearance:none;background-image:linear-gradient(45deg,transparent 50%,var(--gold) 50%),linear-gradient(135deg,var(--gold) 50%,transparent 50%);background-position:calc(100% - 12px) 50%,calc(100% - 7px) 50%;background-size:5px 5px,5px 5px;background-repeat:no-repeat;padding-right:24px;cursor:pointer;}

.sb-radio-group{display:flex;flex-wrap:wrap;gap:8px;}
.sb-radio{flex:1;min-width:calc(50% - 4px);}
.sb-radio input{display:none;}
.sb-radio label{display:block;padding:8px 12px;background:var(--paper-2);border:.5px solid var(--line);border-radius:4px;cursor:pointer;font-family:var(--font-cn);font-size:13px;color:var(--ink-sub);text-align:center;letter-spacing:1px;transition:all .2s;}
.sb-radio input:checked + label{background:var(--ink);color:var(--paper-2);border-color:var(--ink);}
.sb-radio label:hover{border-color:var(--gold);}

.sb-submit{display:block;width:100%;margin-top:36px;background:var(--ink);color:var(--paper-2);border:none;padding:16px 24px;font-family:var(--font-cn);font-size:15px;letter-spacing:6px;cursor:pointer;border-radius:2px;box-shadow:0 4px 12px rgba(31,41,55,.15);transition:all .2s;}
.sb-submit:hover{background:var(--gold);color:var(--paper);letter-spacing:8px;}
.sb-submit-en{display:block;font-family:var(--font-en);font-size:9px;letter-spacing:3px;font-weight:400;margin-top:4px;opacity:.7;text-transform:uppercase;}

.sb-setup-foot{margin-top:24px;text-align:center;font-family:var(--font-en);font-size:9px;letter-spacing:3px;color:var(--ink-faint);text-transform:uppercase;}
