  <div class="sb-setup-quote">在这座岛上，每一寸真心都标着汇率。<br>请填写你的入场资料。系统会据此生成你的第一个早晨、<br>第一笔账单，和第一条来自陌生人的私信。</div>

  <div class="sb-row sb-pair">
    <div class="sb-row">
      <div class="sb-label"><span class="sb-label-en">Name</span><span class="sb-label-cn">英文名</span></div>
      <input class="sb-input" autocomplete="off" data-lpignore="true" data-1p-ignore id="sb-name-en" placeholder="e.g. Aria, Cleo, Vivienne...">
    </div>
    <div class="sb-row">
      <div class="sb-label"><span class="sb-label-en">中文名</span></div>
      <input class="sb-input" autocomplete="off" data-lpignore="true" data-1p-ignore id="sb-name-cn" placeholder="可留空">
    </div>
  </div>

  <div class="sb-row sb-pair">
    <div class="sb-row">
      <div class="sb-label"><span class="sb-label-en">Age</span><span class="sb-label-cn">年龄</span></div>
      <input class="sb-input" autocomplete="off" data-lpignore="true" data-1p-ignore id="sb-age" type="number" placeholder="22" value="22" min="18" max="40">
    </div>
    <div class="sb-row">
      <div class="sb-label"><span class="sb-label-en">Visa</span><span class="sb-label-cn">签证</span></div>
      <select class="sb-select" id="sb-visa">
        <option>F-1</option><option>J-1</option><option>OPT</option><option>CPT</option><option>B1/B2</option><option>Other</option>
      </select>
    </div>
  </div>

  <div class="sb-row">
    <div class="sb-label"><span class="sb-label-en">School</span><span class="sb-label-cn">学校</span></div>
    <input class="sb-input" autocomplete="off" data-lpignore="true" data-1p-ignore id="sb-school" placeholder="NYU / Columbia / Parsons / Juilliard / FIT / Pratt / ...">
  </div>

  <div class="sb-row sb-pair">
    <div class="sb-row">
      <div class="sb-label"><span class="sb-label-en">Major</span><span class="sb-label-cn">专业</span></div>
      <input class="sb-input" autocomplete="off" data-lpignore="true" data-1p-ignore id="sb-major" placeholder="e.g. Finance, Fashion, Film...">
    </div>
    <div class="sb-row">
      <div class="sb-label"><span class="sb-label-en">Year</span><span class="sb-label-cn">年级</span></div>
      <input class="sb-input" autocomplete="off" data-lpignore="true" data-1p-ignore id="sb-year" placeholder="e.g. 硕一 / 本三 / OPT 第一年">
    </div>
  </div>

  <div class="sb-row">
    <div class="sb-label"><span class="sb-label-en">Neighborhood</span><span class="sb-label-cn">居住街区</span></div>
    <select class="sb-select" id="sb-hood">
      <option>Upper East Side · UES</option>
      <option>Upper West Side · UWS</option>
      <option>Lower East Side · LES</option>
      <option>SoHo</option>
      <option>West Village</option>
      <option>Williamsburg, Brooklyn</option>
      <option>Astoria, Queens</option>
      <option>Jersey City, NJ</option>
      <option>Long Island City · LIC</option>
    </select>
  </div>

  <div class="sb-row">
    <div class="sb-label"><span class="sb-label-en">Appearance</span><span class="sb-label-cn">外形</span></div>
    <textarea class="sb-textarea" autocomplete="off" data-lpignore="true" data-1p-ignore id="sb-look" placeholder="身高 / 体型 / 风格关键词。例：168cm，瘦削，oversized 大衣 + chunky boots，黑色长直发，气质偏冷感"></textarea>
  </div>

  <div class="sb-row">
    <div class="sb-label"><span class="sb-label-en">Background</span><span class="sb-label-cn">家庭背景</span></div>
    <div class="sb-radio-group">
      <div class="sb-radio"><input type="radio" name="sb-bg" id="bg1" value="rich"><label for="bg1">家境优渥<br><small style="opacity:.6;font-family:var(--font-en);font-size:9px;letter-spacing:1px">Family pays tuition</small></label></div>
      <div class="sb-radio"><input type="radio" name="sb-bg" id="bg2" value="middle" checked><label for="bg2">中产<br><small style="opacity:.6;font-family:var(--font-en);font-size:9px;letter-spacing:1px">Loans + part-time</small></label></div>
      <div class="sb-radio"><input type="radio" name="sb-bg" id="bg3" value="self"><label for="bg3">独立<br><small style="opacity:.6;font-family:var(--font-en);font-size:9px;letter-spacing:1px">Fully on your own</small></label></div>
      <div class="sb-radio"><input type="radio" name="sb-bg" id="bg4" value="cut"><label for="bg4">被切断<br><small style="opacity:.6;font-family:var(--font-en);font-size:9px;letter-spacing:1px">Family disowned</small></label></div>
