<script>
(function(){
var W = window.parent || window;

var RENT_MAP = {
  'Upper East Side · UES': 3200,
  'Upper West Side · UWS': 2800,
  'Lower East Side · LES': 2400,
  'SoHo': 3500,
  'West Village': 3000,
  'Williamsburg, Brooklyn': 2200,
  'Astoria, Queens': 1800,
  'Jersey City, NJ': 1600,
  'Long Island City · LIC': 2000,
};

var BAL_MAP = { rich: 12000, middle: 3840, self: 1200, cut: 380 };
var BURN_MAP = { rich: 8000, middle: 6500, self: 5200, cut: 4800 };

window.sbSubmitProfile = async function() {
  var en = document.getElementById('sb-name-en').value.trim() || 'Aria';
  var cn = document.getElementById('sb-name-cn').value.trim() || '';
  var age = document.getElementById('sb-age').value || '22';
  var visa = document.getElementById('sb-visa').value;
  var school = document.getElementById('sb-school').value.trim() || 'NYU';
  var major = document.getElementById('sb-major').value.trim() || 'Finance';
  var year = document.getElementById('sb-year').value.trim() || '硕一';
  var hood = document.getElementById('sb-hood').value;
  var look = document.getElementById('sb-look').value.trim() || '待补充';
  var bgRadio = document.querySelector('input[name="sb-bg"]:checked');
  var bg = bgRadio ? bgRadio.value : 'middle';
  var bgLabel = {rich:'家境优渥',middle:'中产',self:'独立',cut:'被切断'}[bg];

  var rent = RENT_MAP[hood] || 2400;
  var balance = BAL_MAP[bg] || 3840;
  var burn = BURN_MAP[bg] || 6500;

  // 初始化游戏状态 → 写入聊天变量 sb（随聊天存档，generator/phone 共享读取）
  var initData = {
    profile: { name_en: en, name_cn: cn, age: age, visa: visa, school: school, major: major, year: year, hood: hood, look: look, bg: bg, bg_label: bgLabel },
    wallet: {
      balance: balance,
      bills: [
        { name: hood.split('\xB7')[0].trim() + ' Rent', amount: rent, days_left: 15, urgent: rent > balance },
        { name: school + ' Tuition', amount: 3500, days_left: 20, urgent: false },
        { name: 'Chase Credit Card', amount: 800, days_left: 10, urgent: true },
      ],
      transactions: [],
    },
    npcs: {},
    wardrobe: { items: [], current_outfit: [] },
    beauty: { charm: 50, treatments: [] },
    lifestyle: { apartment: 'studio', monthly_burn: burn },
    schedule: [],
    sugarelite: { subscribed: false, tier: 'none' },
    game: { day: 1, time: 'Wed 11:47 PM', date: '2026-04-26', nsfw: true },
    leaderboard: { synced: false, username: '' },
    _parsed: {},
  };
  try {
    var wrote = false;
    if (typeof insertOrAssignVariables === 'function') { insertOrAssignVariables({ sb: initData }, { type: 'chat' }); wrote = true; }
    if (!wrote && W.insertOrAssignVariables) { W.insertOrAssignVariables({ sb: initData }, { type: 'chat' }); wrote = true; }
    if (!wrote && W.TavernHelper && W.TavernHelper.insertOrAssignVariables) { W.TavernHelper.insertOrAssignVariables({ sb: initData }, { type: 'chat' }); wrote = true; }
    if (!wrote && typeof replaceVariables === 'function') { var v = (typeof getVariables === 'function' ? getVariables({ type: 'chat' }) : {}) || {}; v.sb = initData; replaceVariables(v, { type: 'chat' }); }
  } catch(e) {
    console.error('[SB-NYC V3] init sb variable error', e);
  }

  // 发给主线 LLM：只写开场氛围散文，不写任何私信（私信由 generator 独立生成）
  var displayName = en + (cn ? ' / ' + cn : '');
  var msg = '【入场资料】' + displayName + '，' + age + '岁，' + visa + '签证，' + school + ' ' + major + ' ' + year + '，住 ' + hood + '。外形：' + look + '。家庭：' + bgLabel + '。\n\n'
    + '现在是一个周三深夜，{{user}} 刚回到 ' + hood + ' 的公寓。请写一段 400-600 字的开场氛围散文：她的居所、她此刻的状态、这座城市深夜的质感。'
    + '不要写任何手机私信、对话清单或 "名字：台词"——手机消息由系统单独生成。在她伸手去拿手机查看消息时收笔。';

  try {
    var h = W.TavernHelper;
    if (h && h.triggerSlash) {
      h.triggerSlash('/send ' + msg + ' || /trigger');
    } else {
      var ctx = W.SillyTavern && W.SillyTavern.getContext && W.SillyTavern.getContext();
      if (ctx && ctx.executeSlashCommandsWithOptions) ctx.executeSlashCommandsWithOptions('/send ' + msg + ' || /trigger');
    }
  } catch(e) {
    console.error('[SB-NYC v4] send error', e);
    alert('提交失败，请检查酒馆助手是否启用');
  }

  // 首批私信改用内置种子（零API调用——开场时主线正在生成正文，再叠私信/论坛调用必撞429）
  // 之后玩家回复某人或点手机🔄，才会真正调API
  setTimeout(function(){
    try {
      if (typeof eventEmit === 'function') eventEmit('sb_seed_dm');
      else if (W.eventEmit) W.eventEmit('sb_seed_dm');
      else if (W.TavernHelper && W.TavernHelper.eventEmit) W.TavernHelper.eventEmit('sb_seed_dm');
    } catch(e) { console.error('[SB-NYC v4] seed DM trigger error', e); }
  }, 400);
};
})();
</script>
</body>
</html>
