function mergeRequests(batch) {
  var reasons = [], focus = [];
  for (var i = 0; i < batch.length; i++) {
    var p = batch[i] || {};
    if (p.reason) reasons.push(p.reason);
    if (Array.isArray(p.focus)) for (var f = 0; f < p.focus.length; f++) if (focus.indexOf(p.focus[f]) === -1) focus.push(p.focus[f]);
