async function generateMagOnce(sb, plot, strict, onlyKeys) {
  var keys = (onlyKeys && onlyKeys.length) ? onlyKeys : Object.keys(MAG_SPECS);
  var sys =
    '你是 Sugar Baby 模拟器里两份内容的撰稿人：\n' +
