  function onlineCfg() {
    var c = {};
    try { var raw = VIEW.localStorage.getItem('sbnyc_online'); if (raw) c = JSON.parse(raw) || {}; } catch (e) {}
    return { off: !!c.off, server: c.server || '', key: c.key || '', handle: c.handle || '', token: c.token || '', blurb: c.blurb || '' };
